"use strict";const e=require("../common/vendor.js"),n=require("../api/auth.js");exports.useAuth=function(){const t=e.ref(e.index.getStorageSync("token")||""),o=e.ref(e.index.getStorageSync("userInfo")||null),r=e.computed(()=>!!t.value);return{token:t,userInfo:o,isLoggedIn:r,checkLogin:()=>{t.value=e.index.getStorageSync("token")||"",o.value=e.index.getStorageSync("userInfo")||null},login:async()=>{try{const r=await new Promise((n,t)=>{e.index.login({provider:"weixin",success:n,fail:t})}),s=await n.wechatLogin(r.code);return t.value=s.token,o.value=s.user,e.index.setStorageSync("token",s.token),e.index.setStorageSync("userInfo",s.user),e.index.showToast({title:"登录成功",icon:"success"}),!0}catch(r){return console.error(r),e.index.showToast({title:"登录失败",icon:"none"}),!1}},logout:()=>{e.index.removeStorageSync("token"),e.index.removeStorageSync("userInfo"),t.value="",o.value=null,e.index.showToast({title:"已退出",icon:"success"})}}},exports.useUserType=function(){const e={student:"学生",teacher:"教师",staff:"教职工"};return{getUserTypeName:n=>e[n]||"用户"}};
